using System; using System.Collections.Generic;
class Program { static string MinWindow(string s, string t) { var need = new int[128]; int missing = t.Length; foreach (char ch in t) need[ch]++; int left = 0, bestStart = 0, bestLen = s.Length + 1; for (int right = 0; right < s.Length; right++) { int c = s[right]; if (need[c] > 0) missing--; need[c]--; while (missing == 0) { if (right - left + 1 < bestLen) { bestStart = left; bestLen = right - left + 1; } int lc = s[left]; need[lc]++; if (need[lc] > 0) missing++; left++; } } return bestLen > s.Length ? "" : s.Substring(bestStart, bestLen); }
static void Main() { var lines = Console.In.ReadToEnd().Split(new[] { "\r\n", "\n" }, StringSplitOptions.None); if (lines.Length > 0 && lines[0] != "") { int t = int.Parse(lines[0]); var outp = new List<string>(); for (int i = 0; i < t; i++) outp.Add(MinWindow(lines[1 + 2*i], lines[2 + 2*i])); Console.Write(string.Join("\n", outp)); } } }
